import requests

# Set up RabbitMQ Management HTTP API endpoint and credentials
management_url = "http://localhost:15672"
username = "guest"
password = "guest"

# Create virtual hosts for different applications
vhosts = ["app1", "app2"]
for vhost in vhosts:
    # Create the virtual host
    response = requests.post(f"{management_url}/api/vhosts/{vhost}", auth=(username, password))
    if response.status_code != 204:
        print("Error creating virtual host")
        break

# Set up users and grant permissions for queue operations
users = ["user1", "user2"]
for user in users:
    # Create the user
    response = requests.post(f"{management_url}/api/users/{user}", auth=(username, password))
    if response.status_code != 204:
        print("Error creating user")
        break
    
    # Grant permissions for queue operations
    response = requests.put(f"{management_url}/api/permissions/{vhost}/{user}", auth=(username, password), json={
        "configure": ".*",
        "write": ".*",
        "read": ".*"
    })
    if response.status_code != 204:
        print("Error granting permissions")
        break